import time, json, requests
from azure.identity import DefaultAzureCredential

TEAMS_WEBHOOK_URL = "https://outlook.webhook.office.com/webhookb2/..."  # from Teams channel

def post_to_teams(title: str, facts: list[tuple[str, str]], color: str = "0078D4") -> None:
    """Post an Adaptive Card to a Teams channel."""
    card = {
        "type": "message",
        "attachments": [{
            "contentType": "application/vnd.microsoft.card.adaptive",
            "content": {
                "$schema": "http://adaptivecards.io/schemas/adaptive-card.json",
                "type": "AdaptiveCard",
                "version": "1.2",
                "body": [
                    {"type": "TextBlock", "text": title, "weight": "Bolder", "size": "Medium", "color": "Accent"},
                    {"type": "FactSet", "facts": [{"title": k, "value": v} for k, v in facts]},
                ],
            },
        }],
    }
    requests.post(TEAMS_WEBHOOK_URL, json=card, timeout=10)

def watch_ticket_and_notify(
    subscription_id: str,
    ticket_name: str,
    poll_seconds: int = 120,
) -> None:
    """Poll ticket status and post Teams notifications on state changes."""
    credential = DefaultAzureCredential()
    token = credential.get_token("https://management.azure.com/.default").token
    headers = {"Authorization": f"Bearer {token}"}

    url = (
        f"https://management.azure.com/subscriptions/{subscription_id}"
        f"/providers/Microsoft.Support/supportTickets/{ticket_name}?api-version=2020-04-01"
    )
    last = {}

    post_to_teams(
        title=f"Support ticket opened: {ticket_name}",
        facts=[("Subscription", subscription_id), ("Ticket", ticket_name), ("Status", "created")],
    )

    while True:
        resp = requests.get(url, headers=headers, timeout=15)
        resp.raise_for_status()
        props = resp.json().get("properties", {})
        current = {
            "status": props.get("status"),
            "engineer": props.get("supportEngineer", {}).get("emailAddress"),
        }

        if current != last:
            post_to_teams(
                title=f"Support ticket update: {ticket_name}",
                facts=[
                    ("Status", current["status"] or "—"),
                    ("Engineer", current["engineer"] or "unassigned"),
                    ("Severity", props.get("severity", "—")),
                ],
                color="00B050" if current["status"] == "closed" else "FF0000",
            )
            last = current

        if current["status"] in ("closed", "cancelled"):
            break
        time.sleep(poll_seconds)
